actionConfiguration.body:
{
  "aggregate": "activity_center",
  "pipeline": [
  {
    $match: {{ autofill_total_qs_filter_js.getMatchQuery() }}
  },
  {
    $project:
      {
        client_id: 1,
        created_by: 1,
        document: "$activity_meta.documentId",
        id: "$run_id",
        created_date: {
          $dateToString: {
            format: "%Y-%m-%d",
            date: {
              $toDate: "$created_at",
            },
          },
        },
        completed_questions:
          "$activity_stats.completed",
        answered_questions:
          "$activity_stats.answered",
        unanswered_questions:
          "$activity_stats.unanswered",
        total_time: {
          $divide: [
            {
              $subtract: [
                "$updated_at",
                "$created_at",
              ],
            },
            1000,
          ],
        },
      },
  },
  {
    $group: {
      _id: {
        created_date: "$created_date",
        created_by: "$created_by",
        client_id: "$client_id",
      },
      totalQuestions: {
        $sum: "$completed_questions",
      },
      totalQuestionsAnswered: {
        $sum: "$answered_questions",
      },
      totalTime: {
        $sum: "$total_time",
      },
      totalRuns: {
        $sum: 1,
      },
      autoFillDocuments: {
        $addToSet: "$document",
      },
    },
  },
  {
    $project: {
      created: "$_id.created_dt",
      clientId: "$_id.clientId",
      userId: "$_id.userId",
      totalQuestions: "$totalQuestions",
      totalQuestionsAnswered:
        "$totalQuestionsAnswered",
      totalRuns: "$totalRuns",
      totalDocuments: {
        $size: "$autoFillDocuments",
      },
      averageResponseTime: {
        $divide: [
          "$totalTime",
          "$totalQuestions",
        ],
      },
    },
  },
],
  "cursor": {}
}

arrayPipelines.data:
[
  {
    $match: {{ autofill_total_qs_filter_js.getMatchQuery() }}
  },
  {
    $project: {
      client_id: 1,
      created_by: 1,
		  document: "$activity_meta.name",
      id: "$run_id",
		tx_consumed: 1,
      created_date: {
        $dateToString: {
          format: "%Y-%m-%d",
          date: {
            $toDate: "$created_at",
          },
        },
      },
      completed_questions: "$activity_stats.completed",
      answered_questions: "$activity_stats.answered",
      unanswered_questions: "$activity_stats.unanswered",
      total_time: {
        $divide: [
          {
            $subtract: ["$updated_at", "$created_at"],
          },
          1000,
        ],
      },
    },
  },
  {
    $group: {
      _id: {
        created_date: "$created_date",
        created_by: "$created_by",
        client_id: "$client_id",
      },
      totalQuestions: { $sum: "$completed_questions" },
      totalQuestionsAnswered: { $sum: "$answered_questions" },
      totalTime: { $sum: "$total_time" },
      totalRuns: { $sum: 1 },
      autoFillDocuments: { $addToSet: "$document" },
			tx_consumed: { $sum: "$tx_consumed" }
    },
  },
  {
    $facet: {
      groupData: [
        {
          $project: {
            created: "$_id.created_date",
            clientId: "$_id.client_id",
            userId: "$_id.created_by",
						tx_consumed: 1,
            totalQuestions: "$totalQuestions",
            totalQuestionsAnswered: "$totalQuestionsAnswered",
            totalRuns: "$totalRuns",
            totalDocuments: { $size: "$autoFillDocuments" },
            averageResponseTime: {
              $cond: {
                if: { $eq: ["$totalQuestions", 0] },
                then: 0,
                else: { $divide: ["$totalTime", "$totalQuestions"] },
              },
            },
            autoFillDocuments: "$autoFillDocuments"
          },
        },
      ],
      uniqueDocuments: [
        {
          $group: {
            _id: null,
            allDocuments: { $addToSet: "$autoFillDocuments" },
          },
        },
        {
          $project: {
            totalUniqueDocuments: {
              $size: {
                $reduce: {
                  input: "$allDocuments",
                  initialValue: [],
                  in: { $setUnion: ["$$value", "$$this"] },
                },
              },
            },
          },
        },
      ],
    },
  },
  {
    $project: {
      groupData: 1,
      totalUniqueDocuments: {
        $arrayElemAt: ["$uniqueDocuments.totalUniqueDocuments", 0],
      },
    },
  },
  {
    $unwind: "$groupData",
  },
  {
    $addFields: {
      "groupData.totalUniqueDocuments": "$totalUniqueDocuments",
    },
  },
  {
    $replaceRoot: { newRoot: "$groupData" },
  },
]

